22	pub async fn check_availability(pool: &MySqlPool, resource_uuid: &str, date: &str) -> Result<Vec<AvailabilitySlot>, AppError> {
23	    let resource = booking_repo::find_resource_by_uuid(pool, resource_uuid).await?
24	        .ok_or_else(|| AppError::NotFound("Resource not found".to_string()))?;
25	
26	    let start_str = format!("{} {}", date, resource.open_time.format("%H:%M:%S"));
27	    let close_str = format!("{} {}", date, resource.close_time.format("%H:%M:%S"));
28	
29	    let existing = booking_repo::find_conflicts(pool, resource.id, &start_str, &close_str).await?;
30	    let blackouts = booking_repo::list_blackouts(pool, resource.id).await?;
31	
32	    // Generate hourly slots
33	    let mut slots = Vec::new();
34	    let open_hour = resource.open_time.hour() as i64;
35	    let close_hour = resource.close_time.hour() as i64;
36	
37	    for hour in open_hour..close_hour {
38	        let slot_start = format!("{} {:02}:00:00", date, hour);
39	        let slot_end = format!("{} {:02}:00:00", date, hour + 1);
40	
41	        let conflict = existing.iter().any(|b| {
42	            let bs = b.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
43	            let be = b.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
44	            bs < slot_end && be > slot_start
45	        });
46	
47	        let blackout = blackouts.iter().any(|bl| {
48	            let bs = bl.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
49	            let be = bl.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
50	            bs < slot_end && be > slot_start
51	        });
52	
53	        let (available, reason) = if blackout {
54	            (false, Some("Maintenance blackout".to_string()))
55	        } else if conflict {
56	            (false, Some("Already booked".to_string()))
57	        } else {
58	            (true, None)
59	        };
60	
61	        slots.push(AvailabilitySlot {
62	            start: slot_start, end: slot_end, available, conflict_reason: reason,
63	        });
64	    }
65	    Ok(slots)
66	}
