68	pub async fn create_booking(
69	    pool: &MySqlPool, req: &CreateBookingRequest, user_id: i64, correlation_id: Option<&str>,
70	) -> Result<BookingResponse, AppError> {
71	    let resource = booking_repo::find_resource_by_uuid(pool, &req.resource_uuid).await?
72	        .ok_or_else(|| AppError::NotFound("Resource not found".to_string()))?;
73	
74	    // Check user doesn't have active booking restriction
75	    if booking_repo::has_active_restriction(pool, user_id, "booking_suspended").await? {
76	        return Err(AppError::Forbidden("You have an active booking restriction due to policy breaches".to_string()));
77	    }
78	
79	    // Parse times
80	    let start_dt = parse_datetime(&req.start_time)?;
81	    let end_dt = parse_datetime(&req.end_time)?;
82	    let now = Utc::now().naive_utc();
83	
84	    // Validate: end > start
85	    if end_dt <= start_dt {
86	        return Err(AppError::Validation("End time must be after start time".to_string()));
87	    }
88	
89	    // Validate: max 90 days ahead
90	    let max_future = now + Duration::days(MAX_ADVANCE_DAYS);
91	    if start_dt > max_future {
92	        return Err(AppError::Validation(format!("Cannot book more than {} days in advance", MAX_ADVANCE_DAYS)));
93	    }
94	
95	    // Validate: within operating hours
96	    let start_time_only = start_dt.time();
97	    let end_time_only = end_dt.time();
98	    if start_time_only < resource.open_time || end_time_only > resource.close_time {
99	        return Err(AppError::Validation(format!(
100	            "Booking must be within resource hours: {} - {}",
101	            resource.open_time.format("%H:%M"), resource.close_time.format("%H:%M")
102	        )));
103	    }
104	
105	    // Validate: max duration for room type
106	    let duration_hours = (end_dt - start_dt).num_hours();
107	    if duration_hours > resource.max_booking_hours as i64 {
108	        return Err(AppError::Validation(format!(
109	            "Maximum booking duration for this resource is {} hours", resource.max_booking_hours
110	        )));
111	    }
112	
113	    // Validate: max 2 active reservations per user per resource
114	    let active_count = booking_repo::count_active_bookings_for_resource(pool, user_id, resource.id).await?;
115	    if active_count >= MAX_ACTIVE_PER_RESOURCE as i64 {
116	        return Err(AppError::Validation(format!(
117	            "Maximum {} active reservations per resource", MAX_ACTIVE_PER_RESOURCE
118	        )));
119	    }
120	
121	    let uuid = Uuid::new_v4().to_string();
122	    let start_str = start_dt.format("%Y-%m-%d %H:%M:%S").to_string();
123	    let end_str = end_dt.format("%Y-%m-%d %H:%M:%S").to_string();
124	
125	    // Atomic booking with conflict prevention
126	    booking_repo::create_booking_atomic(
127	        pool, &uuid, resource.id, user_id, &req.title,
128	        req.description.as_deref(), &start_str, &end_str,
129	    ).await.map_err(|e| {
130	        let msg = e.to_string();
131	        if msg.contains("BOOKING_CONFLICT") {
132	            AppError::Validation("Time slot conflict: this resource is already booked for the requested time".to_string())
133	        } else if msg.contains("BLACKOUT_CONFLICT") {
134	            AppError::Validation("Resource is under maintenance during the requested time".to_string())
135	        } else {
136	            AppError::Database(e)
137	        }
138	    })?;
139	
140	    let _ = audit_repo::create_audit_log(
141	        pool, &Uuid::new_v4().to_string(), Some(user_id), "booking.create",
142	        "booking", None, None,
143	        Some(&serde_json::json!({"resource": resource.name, "start": start_str, "end": end_str})),
144	        None, None, correlation_id,
145	    ).await;
146	
147	    let _ = notification_service::notify_user(
148	        pool, user_id,
149	        "Booking Confirmed",
150	        &format!("Your booking '{}' has been confirmed.", req.title),
151	        "booking", Some("booking"), Some(&uuid),
152	    ).await;
153	
154	    Ok(BookingResponse {
155	        uuid, resource_id: resource.id, resource_name: Some(resource.name),
156	        booked_by: user_id, title: req.title.clone(),
157	        description: req.description.clone(),
158	        start_time: start_str, end_time: end_str,
159	        status: "confirmed".to_string(), reschedule_count: 0,
160	        created_at: Utc::now().format("%Y-%m-%dT%H:%M:%S").to_string(),
161	    })
162	}
