164	pub async fn reschedule_booking(
165	    pool: &MySqlPool, booking_uuid: &str, req: &RescheduleRequest, user_id: i64,
166	) -> Result<(), AppError> {
167	    let booking = booking_repo::find_booking_by_uuid(pool, booking_uuid).await?
168	        .ok_or_else(|| AppError::NotFound("Booking not found".to_string()))?;
169	
170	    if booking.booked_by != user_id {
171	        return Err(AppError::Forbidden("You can only reschedule your own bookings".to_string()));
172	    }
173	
174	    if booking.reschedule_count >= MAX_RESCHEDULES {
175	        return Err(AppError::Validation(format!("Maximum {} reschedules allowed", MAX_RESCHEDULES)));
176	    }
177	
178	    if booking.status != "confirmed" {
179	        return Err(AppError::Validation("Only confirmed bookings can be rescheduled".to_string()));
180	    }
181	
182	    let new_start = parse_datetime(&req.new_start_time)?;
183	    let new_end = parse_datetime(&req.new_end_time)?;
184	
185	    if new_end <= new_start {
186	        return Err(AppError::Validation("End time must be after start time".to_string()));
187	    }
188	
189	    let resource = booking_repo::find_resource_by_id(pool, booking.resource_id).await?
190	        .ok_or_else(|| AppError::Internal("Resource not found".to_string()))?;
191	
192	    // Check operating hours
193	    if new_start.time() < resource.open_time || new_end.time() > resource.close_time {
194	        return Err(AppError::Validation("New time must be within resource operating hours".to_string()));
195	    }
196	
197	    // Check duration
198	    let duration = (new_end - new_start).num_hours();
199	    if duration > resource.max_booking_hours as i64 {
200	        return Err(AppError::Validation(format!("Max {} hours", resource.max_booking_hours)));
201	    }
202	
203	    let new_start_str = new_start.format("%Y-%m-%d %H:%M:%S").to_string();
204	    let new_end_str = new_end.format("%Y-%m-%d %H:%M:%S").to_string();
205	
206	    let orig_start = booking.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
207	    let orig_end = booking.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
208	
209	    booking_repo::reschedule_booking_atomic(
210	        pool, booking.id, booking.resource_id,
211	        &Uuid::new_v4().to_string(),
212	        booking.reschedule_count + 1,
213	        user_id,
214	        &orig_start, &orig_end,
215	        &new_start_str, &new_end_str,
216	        req.reason.as_deref(),
217	    ).await.map_err(|e| {
218	        if e.to_string().contains("BOOKING_CONFLICT") {
219	            AppError::Validation("New time conflicts with existing booking".to_string())
220	        } else {
221	            AppError::Internal(e.to_string())
222	        }
223	    })?;
224	
225	    Ok(())
226	}
