228	pub async fn cancel_booking(
229	    pool: &MySqlPool, booking_uuid: &str, user_id: i64, role: &str, correlation_id: Option<&str>,
230	) -> Result<(), AppError> {
231	    let booking = booking_repo::find_booking_by_uuid(pool, booking_uuid).await?
232	        .ok_or_else(|| AppError::NotFound("Booking not found".to_string()))?;
233	
234	    if booking.booked_by != user_id && role != "admin" {
235	        return Err(AppError::Forbidden("Not your booking".to_string()));
236	    }
237	
238	    if booking.status == "cancelled" {
239	        return Err(AppError::Validation("Booking already cancelled".to_string()));
240	    }
241	
242	    booking_repo::update_booking_status(pool, booking.id, "cancelled").await?;
243	
244	    // Late cancellation check: within 2 hours of start creates a breach
245	    let now = Utc::now().naive_utc();
246	    let hours_until_start = (booking.start_time - now).num_hours();
247	
248	    if hours_until_start < LATE_CANCEL_HOURS && booking.start_time > now {
249	        let breach_uuid = Uuid::new_v4().to_string();
250	        booking_repo::create_breach(
251	            pool, &breach_uuid, booking.booked_by, Some(booking.id),
252	            "late_cancellation", "medium",
253	            &format!("Booking cancelled within {} hours of start time", LATE_CANCEL_HOURS),
254	        ).await?;
255	
256	        let _ = notification_service::notify_user(
257	            pool, booking.booked_by,
258	            "Late Cancellation Recorded",
259	            "A late cancellation breach has been recorded on your account.",
260	            "booking", None, None,
261	        ).await;
262	
263	        // Check if user hit breach threshold -> auto-restrict
264	        let breach_count = booking_repo::count_recent_breaches(pool, booking.booked_by, BREACH_WINDOW_DAYS).await?;
265	        if breach_count >= BREACH_THRESHOLD {
266	            let already_restricted = booking_repo::has_active_restriction(pool, booking.booked_by, "booking_suspended").await?;
267	            if !already_restricted {
268	                let expires = (Utc::now() + Duration::days(30)).format("%Y-%m-%d %H:%M:%S").to_string();
269	                booking_repo::create_restriction(
270	                    pool, &Uuid::new_v4().to_string(), booking.booked_by,
271	                    "booking_suspended",
272	                    &format!("{} breaches in {} days triggered automatic booking suspension", breach_count, BREACH_WINDOW_DAYS),
273	                    user_id, &Utc::now().format("%Y-%m-%d %H:%M:%S").to_string(),
274	                    Some(&expires), breach_count as i32, true,
275	                ).await?;
276	
277	                let _ = security_repo::create_security_event(
278	                    pool, &Uuid::new_v4().to_string(), "booking_auto_restriction", "warning",
279	                    Some(booking.booked_by), None,
280	                    &format!("Auto-restricted: {} breaches in {} days", breach_count, BREACH_WINDOW_DAYS),
281	                    None, correlation_id,
282	                ).await;
283	
284	                let _ = notification_service::notify_user(
285	                    pool, booking.booked_by,
286	                    "Booking Privileges Suspended",
287	                    &format!("{} policy breaches in {} days triggered an automatic booking suspension.", breach_count, BREACH_WINDOW_DAYS),
288	                    "booking", None, None,
289	                ).await;
290	            }
291	        }
292	    }
293	
294	    let _ = audit_repo::create_audit_log(
295	        pool, &Uuid::new_v4().to_string(), Some(user_id), "booking.cancel",
296	        "booking", Some(booking.id), None,
297	        Some(&serde_json::json!({"hours_until_start": hours_until_start})),
298	        None, None, correlation_id,
299	    ).await;
300	
301	    Ok(())
302	}
