63	/// Reschedule an existing booking atomically.
64	///
65	/// Acquires a row-level lock on the resource (SELECT FOR UPDATE) inside a
66	/// transaction so that two concurrent reschedules to the same slot cannot both
67	/// pass the conflict check. Returns Ok(()) on success or a `BOOKING_CONFLICT`
68	/// protocol error if the new slot overlaps another booking.
69	pub async fn reschedule_booking_atomic(
70	    pool: &MySqlPool,
71	    booking_id: i64,
72	    resource_id: i64,
73	    reschedule_uuid: &str,
74	    reschedule_number: i32,
75	    requested_by: i64,
76	    orig_start: &str,
77	    orig_end: &str,
78	    new_start: &str,
79	    new_end: &str,
80	    reason: Option<&str>,
81	) -> Result<(), sqlx::Error> {
82	    let mut tx = pool.begin().await?;
83	
84	    // Lock resource row — serializes concurrent reschedule + create operations
85	    sqlx::query("SELECT id FROM resources WHERE id = ? FOR UPDATE")
86	        .bind(resource_id).execute(&mut *tx).await?;
87	
88	    // Conflict check (exclude the booking being rescheduled)
89	    let conflict: Option<(i64,)> = sqlx::query_as(
90	        "SELECT id FROM bookings WHERE resource_id = ? AND id != ? \
91	         AND status IN ('confirmed', 'pending') \
92	         AND start_time < ? AND end_time > ? LIMIT 1"
93	    ).bind(resource_id).bind(booking_id).bind(new_end).bind(new_start)
94	    .fetch_optional(&mut *tx).await?;
95	
96	    if conflict.is_some() {
97	        tx.rollback().await?;
98	        return Err(sqlx::Error::Protocol("BOOKING_CONFLICT: Time slot already booked".to_string()));
99	    }
100	
101	    // Record reschedule history
102	    sqlx::query(
103	        "INSERT INTO booking_reschedules (uuid, booking_id, reschedule_number, requested_by, \
104	         original_start, original_end, new_start, new_end, reason, status) \
105	         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'approved')"
106	    ).bind(reschedule_uuid).bind(booking_id).bind(reschedule_number).bind(requested_by)
107	    .bind(orig_start).bind(orig_end).bind(new_start).bind(new_end).bind(reason)
108	    .execute(&mut *tx).await?;
109	
110	    // Update booking times and reschedule counter atomically
111	    sqlx::query("UPDATE bookings SET start_time = ?, end_time = ?, updated_at = NOW() WHERE id = ?")
112	        .bind(new_start).bind(new_end).bind(booking_id)
113	        .execute(&mut *tx).await?;
114	
115	    sqlx::query("UPDATE bookings SET reschedule_count = reschedule_count + 1, updated_at = NOW() WHERE id = ?")
116	        .bind(booking_id).execute(&mut *tx).await?;
117	
118	    tx.commit().await?;
119	    Ok(())
120	}
