{"file_path": "/home/nahom/Desktop/Others/EaglePointAI/vibe-coding-projects/campus-learn-operations-suite-sys/repo/unit_tests/backend/test_media_validation.py", "content": """"Unit tests for media validation state model."""
import unittest


ALLOWED_MEDIA_TYPES = ["application/pdf", "video/mp4", "image/png"]
MAX_MEDIA_SIZE_BYTES = 500 * 1024 * 1024  # 500 MB

EXTENSION_MAP = {
    "application/pdf": [".pdf"],
    "video/mp4": [".mp4"],
    "image/png": [".png"],
}


def validate_media(file_name, mime_type, file_size_bytes, checksum, file_path):
    """Deterministic media validation matching the Rust validate_media logic.

    Returns (status, validated, errors) tuple.
    """
    errors = []

    # Extension must match MIME type
    expected = EXTENSION_MAP.get(mime_type, [])
    if not any(file_name.lower().endswith(ext) for ext in expected):
        errors.append(f"File extension does not match MIME type {mime_type}")

    # Checksum must be present
    if not checksum:
        errors.append("Checksum is missing")

    # File path must be absolute
    if not file_path.startswith("/"):
        errors.append("File path must be absolute")

    if errors:
        return "failed", False, errors
    return "ready", True, []


def determine_initial_media_status(validated, validation_error):
    """Mirror of course_repo::create_media status derivation."""
    if validation_error:
        return "failed"
    elif validated:
        return "ready"
    else:
        return "pending_scan"


class TestMediaRegistrationDefaults(unittest.TestCase):
    def test_registration_defaults_to_pending_scan(self):
        status = determine_initial_media_status(False, None)
        self.assertEqual(status, "pending_scan")

    def test_validated_true_means_ready(self):
        status = determine_initial_media_status(True, None)
        self.assertEqual(status, "ready")

    def test_validation_error_means_failed(self):
        status = determine_initial_media_status(False, "some error")
        self.assertEqual(status, "failed")


class TestMediaValidation(unittest.TestCase):
    def test_valid_pdf(self):
        status, validated, errors = validate_media(
            "document.pdf", "application/pdf", 1024,
            "abc123checksum", "/uploads/document.pdf"
        )
        self.assertEqual(status, "ready")
        self.assertTrue(validated)
        self.assertEqual(errors, [])

    def test_valid_mp4(self):
        status, validated, errors = validate_media(
            "video.mp4", "video/mp4", 1024,
            "abc123checksum", "/uploads/video.mp4"
        )
        self.assertEqual(status, "ready")
        self.assertTrue(validated)

    def test_valid_png(self):
        status, validated, errors = validate_media(
            "image.png", "image/png", 1024,
            "abc123checksum", "/uploads/image.png"
        )
        self.assertEqual(status, "ready")
        self.assertTrue(validated)

    def test_extension_mismatch_fails(self):
        status, validated, errors = validate_media(
            "photo.jpg", "application/pdf", 1024,
            "abc123checksum", "/uploads/photo.jpg"
        )
        self.assertEqual(status, "failed")
        self.assertFalse(validated)
        self.assertTrue(any("extension" in e.lower() for e in errors))

    def test_missing_checksum_fails(self):
        status, validated, errors = validate_media(
            "document.pdf", "application/pdf", 1024,
            None, "/uploads/document.pdf"
        )
        self.assertEqual(status, "failed")
        self.assertFalse(validated)
        self.assertTrue(any("checksum" in e.lower() for e in errors))

    def test_empty_checksum_fails(self):
        status, validated, errors = validate_media(
            "document.pdf", "application/pdf", 1024,
            "", "/uploads/document.pdf"
        )
        self.assertEqual(status, "failed")
        self.assertFalse(validated)

    def test_relative_path_fails(self):
        status, validated, errors = validate_media(
            "document.pdf", "application/pdf", 1024,
            "abc123checksum", "uploads/document.pdf"
        )
        self.assertEqual(status, "failed")
        self.assertFalse(validated)
        self.assertTrue(any("absolute" in e.lower() for e in errors))

    def test_multiple_errors_combined(self):
        status, validated, errors = validate_media(
            "photo.jpg", "application/pdf", 1024,
            None, "relative/path.jpg"
        )
        self.assertEqual(status, "failed")
        self.assertFalse(validated)
        self.assertEqual(len(errors), 3)

    def test_case_insensitive_extension(self):
        status, validated, errors = validate_media(
            "DOCUMENT.PDF", "application/pdf", 1024,
            "abc123checksum", "/uploads/DOCUMENT.PDF"
        )
        self.assertEqual(status, "ready")
        self.assertTrue(validated)


if __name__ == "__main__":
    unittest.main()
"}

