71	) -> Result<BookingResponse, AppError> {
72	    let resource = booking_repo::find_resource_by_uuid(pool, &req.resource_uuid).await?
73	        .ok_or_else(|| AppError::NotFound("Resource not found".to_string()))?;
74	
75	    // Check user doesn't have active booking restriction
76	    if booking_repo::has_active_restriction(pool, user_id, "booking_suspended").await? {
