82	
83	    // Parse times
84	    let start_dt = parse_datetime(&req.start_time)?;
85	    let end_dt = parse_datetime(&req.end_time)?;
86	    let now = Utc::now().naive_utc();
87	
88	    // Validate: end > start
89	    if end_dt <= start_dt {
90	        return Err(AppError::Validation("End time must be after start time".to_string()));
91	    }
92	
