//!
//! # Threat model
//!
//! This application uses Bearer tokens in the `Authorization` header (not
//! cookies), which inherently mitigates classic CSRF attacks — browsers do not
//! automatically attach custom headers to cross-origin requests. However, as
//! defense-in-depth, this fairing verifies the `Origin` header on all
//! state-changing requests (POST, PUT, PATCH, DELETE) to ensure they originate
//! from the allowed origin.
//!
//! Requests without an `Origin` header (e.g., curl, server-to-server, non-browser)
//! are allowed through since they rely on the Bearer token for authentication.
//! Requests with a mismatched `Origin` are rejected with 403.

use rocket::fairing::{Fairing, Info, Kind};
use rocket::http::Method;
use rocket::{Data, Request};

use crate::config::AppConfig;

pub struct CsrfOriginCheck;

#[rocket::async_trait]
impl Fairing for CsrfOriginCheck {
    fn info(&self) -> Info {
        Info {
            name: "CSRF Origin Check",
            kind: Kind::Request,
        }
    }

    async fn on_request(&self, req: &mut Request<'_>, _data: &mut Data<'_>) {
        // Only check state-changing methods
        let method = req.method();
        if method == Method::Get || method == Method::Head || method == Method::Options {
            return;
        }

        // If no Origin header, the request is from a non-browser client (curl,
        // server-to-server). Auth is enforced by the Bearer token guard.
        let origin = match req.headers().get_one("Origin") {
            Some(o) => o,
            None => return,
        };

        // Compare against the configured allowed origin
        let config = match req.rocket().state::<AppConfig>() {
            Some(c) => c,
            None => return,
        };

        let allowed = std::env::var("ALLOWED_ORIGIN")
            .unwrap_or_else(|_| "http://localhost:3000".to_string());

        if origin != allowed {
            tracing::warn!(
                origin = origin,
                allowed = %allowed,
                method = %method,
                uri = %req.uri(),
                "CSRF origin check failed: request origin does not match allowed origin"
            );
            // Mark the request as failed — Rocket will return 403
            // We set a local cache flag that the error catcher can read
            req.local_cache(|| CsrfRejected(true));
        } else {
            req.local_cache(|| CsrfRejected(false));
        }
    }
}

/// Local cache marker for CSRF rejection.
pub struct CsrfRejected(pub bool);
"}

