37	    async fn on_request(&self, req: &mut Request<'_>, _data: &mut Data<'_>) {
38	        // Only check state-changing methods
39	        let method = req.method();
40	        if method == Method::Get || method == Method::Head || method == Method::Options {
41	            return;
42	        }
43	
44	        // If no Origin header, the request is non-browser. Auth enforced by Bearer token.
45	        let origin = match req.headers().get_one("Origin") {
46	            Some(o) => o,
47	            None => return,
48	        };
49	
50	        let allowed = std::env::var("ALLOWED_ORIGIN")
51	            .unwrap_or_else(|_| "http://localhost:3000".to_string());
52	
53	        if origin != allowed {
54	            tracing::warn!(
55	                origin = origin,
56	                allowed = %allowed,
57	                method = %method,
58	                uri = %req.uri(),
59	                "CSRF: state-changing request from unexpected origin"
60	            );
61	        }
62	    }
63	}
