28	    let data_req = privacy_repo::find_data_request_by_uuid(pool, request_uuid).await?
29	        .ok_or_else(|| AppError::NotFound("Data request not found".to_string()))?;
30	
31	    if data_req.status != "pending" {
32	        return Err(AppError::Validation(format!("Request is already in '{}' status", data_req.status)));
33	    }
34	
35	    if req.approved {
36	        privacy_repo::approve_data_request(pool, data_req.id, admin_id, req.admin_notes.as_deref()).await?;
37	
38	        // Process the request
39	        match data_req.request_type.as_str() {
40	            "export" => {
41	                let path = format!("/data/exports/user_{}_export_{}.json", data_req.user_id, Uuid::new_v4());
42	                privacy_repo::complete_data_request(pool, data_req.id, admin_id, Some(&path)).await?;
43	            }
44	            "delete" => {
45	                privacy_repo::delete_user_sensitive_data(pool, data_req.user_id).await?;
46	                privacy_repo::complete_data_request(pool, data_req.id, admin_id, None).await?;
47	            }
48	            "rectify" => {
49	                privacy_repo::complete_data_request(pool, data_req.id, admin_id, None).await?;
50	            }
51	            _ => {}
52	        }
53	    } else {
54	        privacy_repo::reject_data_request(pool, data_req.id, admin_id, req.admin_notes.as_deref()).await?;
55	    }
56	
57	    let _ = audit_repo::create_audit_log(
58	        pool, &Uuid::new_v4().to_string(), Some(admin_id),
59	        if req.approved { "privacy.request_approved" } else { "privacy.request_rejected" },
60	        "personal_data_request", Some(data_req.id), None,
61	        Some(&serde_json::json!({"type": data_req.request_type, "approved": req.approved})),
62	        None, None, None,
63	    ).await;
64	
65	    Ok(())
66	}
