8	/// Validate that `url` is an approved on-prem endpoint.
9	///
10	/// Allowed forms:
11	/// - Scheme must be `http` or `https`
12	/// - Host must be one of:
13	///   - `localhost`
14	///   - `127.0.0.1`
15	///   - IPv4 in 10.0.0.0/8
16	///   - IPv4 in 172.16.0.0/12 (second octet 16–31)
17	///   - IPv4 in 192.168.0.0/16
18	///   - Bare hostname: alphanumeric + hyphens only, no dots (e.g. `campuslearn-receiver`)
19	///
20	/// Returns `Ok(())` on pass, `Err(reason)` on failure.
21	pub fn validate_webhook_endpoint(url: &str) -> Result<(), String> {
22	    // Check scheme
23	    let rest = if let Some(r) = url.strip_prefix("https://") {
24	        r
25	    } else if let Some(r) = url.strip_prefix("http://") {
26	        r
27	    } else {
28	        return Err(format!(
29	            "webhook endpoint must use http or https scheme; got '{}'",
30	            url.split("://").next().unwrap_or(url)
31	        ));
32	    };
33	
34	    if rest.is_empty() {
35	        return Err("webhook endpoint has an empty host".to_string());
36	    }
37	
38	    // Extract authority (everything before the first '/')
39	    let authority = rest.split('/').next().unwrap_or(rest);
40	
41	    if authority.is_empty() {
42	        return Err("webhook endpoint has an empty authority".to_string());
43	    }
44	
45	    // Strip optional port
46	    let host = if let Some(bracket_end) = authority.find(']') {
47	        // IPv6 literal [::1]:port — we don't allow these; fall through to rejection
48	        &authority[..=bracket_end]
49	    } else {
50	        authority.split(':').next().unwrap_or(authority)
51	    };
52	
53	    if host.is_empty() {
54	        return Err("webhook endpoint has an empty host".to_string());
55	    }
56	
57	    if is_approved_onprem_host(host) {
58	        Ok(())
59	    } else {
60	        Err(format!(
61	            "'{}' is not an approved on-prem host; \
62	             allowed: localhost, 127.0.0.1, private IP ranges (10.x, 172.16-31.x, 192.168.x), \
63	             or a bare intranet hostname (no dots)",
64	            host
65	        ))
66	    }
67	}
68	
69	fn is_approved_onprem_host(host: &str) -> bool {
70	    if host == "localhost" || host == "127.0.0.1" {
71	        return true;
72	    }
73	
74	    // Attempt to parse as IPv4
75	    if let Some(ipv4) = parse_ipv4(host) {
76	        let [a, b, c, d] = ipv4;
77	        return matches!(
78	            (a, b, c, d),
79	            (10, _, _, _)                  // 10.0.0.0/8
80	            | (172, 16..=31, _, _)         // 172.16.0.0/12
81	            | (192, 168, _, _)             // 192.168.0.0/16
82	        );
83	    }
84	
85	    // Bare hostname: alphanumeric and hyphens only, no dots
86	    !host.is_empty()
87	        && !host.contains('.')
88	        && host.chars().all(|c| c.is_alphanumeric() || c == '-')
89	}
90	
91	fn parse_ipv4(s: &str) -> Option<[u8; 4]> {
92	    let parts: Vec<&str> = s.split('.').collect();
93	    if parts.len() != 4 {
94	        return None;
95	    }
96	    let mut octets = [0u8; 4];
97	    for (i, p) in parts.iter().enumerate() {
98	        octets[i] = p.parse::<u8>().ok()?;
99	    }
100	    Some(octets)
101	}
102	
103	pub async fn enqueue_event_webhooks(pool: &MySqlPool, event_type: &str, payload: &serde_json::Value) -> Result<u32, AppError> {
104	    let subscribers = risk_repo::get_subscribers_for_event(pool, event_type).await?;
105	    let mut count = 0u32;
106	
107	    for sub in subscribers {
108	        if sub.channel != "webhook" {
109	            continue;
110	        }
111	        // Use the per-subscription endpoint; skip if not configured.
112	        let target_url = match &sub.target_url {
113	            Some(u) => u.clone(),
114	            None => continue,
115	        };
116	        let payload_str = serde_json::to_string(payload).unwrap_or_default();
117	        // Sign only when a per-subscription secret is configured.
118	        let signature = sub.signing_secret.as_deref().map(|secret| {
119	            hmac_util::compute_signature(secret, &payload_str)
120	        });
121	
122	        webhook_repo::enqueue_webhook(
123	            pool, &Uuid::new_v4().to_string(), sub.id, event_type,
124	            payload, &target_url, signature.as_deref(),
125	        ).await?;
126	        count += 1;
127	    }
128	    Ok(count)
129	}
130	
131	/// Process pending webhooks - retry with backoff
132	pub async fn process_webhook_queue(pool: &MySqlPool) -> Result<(u32, u32), AppError> {
133	    let pending = webhook_repo::get_pending_webhooks(pool, 50).await?;
134	    let mut delivered = 0u32;
135	    let mut failed = 0u32;
136	
137	    for entry in pending {
138	        // Attempt delivery (simplified - in production would use HTTP client)
139	        // Since we're on-prem only, check if target is reachable
140	        let result = attempt_delivery(&entry.target_url, &entry.payload, entry.signature.as_deref()).await;
141	
142	        match result {
143	            Ok(code) => {
144	                webhook_repo::mark_delivered(pool, entry.id, code).await?;
145	                delivered += 1;
146	            }
147	            Err(err) => {
148	                webhook_repo::mark_failed(pool, entry.id, None, Some(&err)).await?;
149	                failed += 1;
150	
151	                if entry.attempts + 1 >= entry.max_attempts {
152	                    let _ = security_repo::create_security_event(
153	                        pool, &Uuid::new_v4().to_string(), "webhook_delivery_failed", "warning",
154	                        None, None, &format!("Webhook dead-lettered after {} attempts: {}", entry.max_attempts, entry.target_url),
155	                        Some(&serde_json::json!({"webhook_id": entry.id, "event_type": entry.event_type})), None,
156	                    ).await;
157	                }
158	            }
159	        }
160	    }
161	
162	    Ok((delivered, failed))
163	}
164	
165	async fn attempt_delivery(url: &str, payload: &serde_json::Value, signature: Option<&str>) -> Result<i32, String> {
166	    let client = reqwest::Client::builder()
167	        .timeout(std::time::Duration::from_secs(10))
168	        .build()
169	        .map_err(|e| e.to_string())?;
170	
171	    let mut builder = client.post(url)
172	        .header("Content-Type", "application/json")
173	        .json(payload);
174	
175	    if let Some(sig) = signature {
176	        builder = builder.header("X-Webhook-Signature", sig);
177	    }
178	
179	    match builder.send().await {
180	        Ok(resp) => Ok(resp.status().as_u16() as i32),
181	        Err(e) => Err(e.to_string()),
182	    }
183	}
