1	use rocket::http::Status;
2	use rocket::request::{FromRequest, Outcome, Request};
3	use rocket::serde::json::Json;
4	use sqlx::MySqlPool;
5	
6	use crate::auth::jwt::{validate_token, Claims};
7	use crate::config::AppConfig;
8	use crate::repositories::rate_limit_repo;
9	use crate::utils::errors::ApiError;
10	
11	pub struct AuthenticatedUser {
12	    pub claims: Claims,
13	}
14	
15	#[rocket::async_trait]
16	impl<'r> FromRequest<'r> for AuthenticatedUser {
17	    type Error = Json<ApiError>;
18	
19	    async fn from_request(req: &'r Request<'_>) -> Outcome<Self, Self::Error> {
20	        let config = req.rocket().state::<AppConfig>().expect("AppConfig not configured");
21	
22	        let token = req.headers().get_one("Authorization")
23	            .and_then(|header| header.strip_prefix("Bearer "));
24	
25	        let claims = match token {
26	            Some(token) => match validate_token(config, token) {
27	                Ok(claims) => claims,
28	                Err(_) => return Outcome::Error((
29	                    Status::Unauthorized,
30	                    Json(ApiError::unauthorized("Invalid or expired token")),
31	                )),
32	            },
33	            None => return Outcome::Error((
34	                Status::Unauthorized,
35	                Json(ApiError::unauthorized("Missing authorization header")),
36	            )),
37	        };
38	
39	        // Rate limiting: applied to every authenticated request in one place.
40	        // All role guards delegate here, so no per-route changes are needed.
41	        let pool = req.rocket().state::<MySqlPool>().expect("DB pool not configured");
42	        let count = rate_limit_repo::increment_request_count(pool, claims.user_id)
43	            .await
44	            .unwrap_or(0);
45	        if count > config.rate_limit_per_minute as i32 {
46	            return Outcome::Error((
47	                Status::TooManyRequests,
48	                Json(ApiError::new(
49	                    Status::TooManyRequests,
50	                    "Rate limit exceeded. Try again in a minute.",
51	                )),
52	            ));
53	        }
54	
55	        Outcome::Success(AuthenticatedUser { claims })
56	    }
57	}
58	
59	// Role-specific guards
60	macro_rules! impl_role_guard {
61	    ($name:ident, $role:expr) => {
62	        pub struct $name {
63	            pub claims: Claims,
64	        }
65	
66	        #[rocket::async_trait]
67	        impl<'r> FromRequest<'r> for $name {
68	            type Error = Json<ApiError>;
69	
70	            async fn from_request(req: &'r Request<'_>) -> Outcome<Self, Self::Error> {
71	                let user = match AuthenticatedUser::from_request(req).await {
72	                    Outcome::Success(u) => u,
73	                    Outcome::Error(e) => return Outcome::Error(e),
74	                    Outcome::Forward(f) => return Outcome::Forward(f),
75	                };
76	
77	                if user.claims.role == $role || user.claims.role == "admin" {
78	                    Outcome::Success(Self { claims: user.claims })
79	                } else {
80	                    Outcome::Error((
81	                        Status::Forbidden,
82	                        Json(ApiError::forbidden("Insufficient permissions")),
83	                    ))
84	                }
85	            }
86	        }
87	    };
88	}
