105	        let user = match AuthenticatedUser::from_request(req).await {
106	            Outcome::Success(u) => u,
107	            Outcome::Error(e) => return Outcome::Error(e),
108	            Outcome::Forward(f) => return Outcome::Forward(f),
109	        };
110	
111	        match user.claims.role.as_str() {
112	            "admin" | "staff_author" => Outcome::Success(Self { claims: user.claims }),
113	            _ => Outcome::Error((
114	                Status::Forbidden,
