121	// A guard that allows reviewers (dept_reviewer, admin)
122	pub struct ReviewerGuard {
123	    pub claims: Claims,
124	}
125	
126	#[rocket::async_trait]
127	impl<'r> FromRequest<'r> for ReviewerGuard {
128	    type Error = Json<ApiError>;
129	
130	    async fn from_request(req: &'r Request<'_>) -> Outcome<Self, Self::Error> {
131	        let user = match AuthenticatedUser::from_request(req).await {
132	            Outcome::Success(u) => u,
133	            Outcome::Error(e) => return Outcome::Error(e),
134	            Outcome::Forward(f) => return Outcome::Forward(f),
135	        };
136	
137	        match user.claims.role.as_str() {
138	            "admin" | "dept_reviewer" => Outcome::Success(Self { claims: user.claims }),
