6	#[derive(Debug, Serialize)]
7	pub struct ApiError {
8	    pub status: u16,
9	    pub error: String,
10	    pub message: String,
11	    #[serde(skip_serializing_if = "Option::is_none")]
12	    pub details: Option<serde_json::Value>,
13	}
14	
15	impl ApiError {
16	    pub fn new(status: Status, message: impl Into<String>) -> Self {
17	        Self {
18	            status: status.code,
19	            error: status.reason_lossy().to_string(),
20	            message: message.into(),
21	            details: None,
22	        }
23	    }
24	
25	    pub fn with_details(mut self, details: serde_json::Value) -> Self {
26	        self.details = Some(details);
27	        self
28	    }
29	
30	    pub fn bad_request(msg: impl Into<String>) -> Self {
31	        Self::new(Status::BadRequest, msg)
32	    }
33	
34	    pub fn unauthorized(msg: impl Into<String>) -> Self {
35	        Self::new(Status::Unauthorized, msg)
36	    }
37	
38	    pub fn forbidden(msg: impl Into<String>) -> Self {
39	        Self::new(Status::Forbidden, msg)
40	    }
41	
42	    pub fn not_found(msg: impl Into<String>) -> Self {
43	        Self::new(Status::NotFound, msg)
44	    }
45	
46	    pub fn internal(msg: impl Into<String>) -> Self {
47	        Self::new(Status::InternalServerError, msg)
48	    }
49	}
50	
51	#[derive(Debug, thiserror::Error)]
52	pub enum AppError {
53	    #[error("Database error: {0}")]
54	    Database(#[from] sqlx::Error),
55	
56	    #[error("Authentication error: {0}")]
57	    Auth(String),
58	
59	    #[error("Validation error: {0}")]
60	    Validation(String),
61	
62	    #[error("Not found: {0}")]
63	    NotFound(String),
64	
65	    #[error("Forbidden: {0}")]
66	    Forbidden(String),
67	
68	    #[error("Internal error: {0}")]
69	    Internal(String),
70	}
71	
72	impl From<AppError> for (Status, Json<ApiError>) {
73	    fn from(err: AppError) -> Self {
74	        tracing::error!(error = %err, "Application error");
75	        match err {
76	            AppError::Database(_) => (
77	                Status::InternalServerError,
78	                Json(ApiError::internal("A database error occurred")),
79	            ),
80	            AppError::Auth(msg) => (Status::Unauthorized, Json(ApiError::unauthorized(msg))),
81	            AppError::Validation(msg) => (Status::BadRequest, Json(ApiError::bad_request(msg))),
82	            AppError::NotFound(msg) => (Status::NotFound, Json(ApiError::not_found(msg))),
83	            AppError::Forbidden(msg) => (Status::Forbidden, Json(ApiError::forbidden(msg))),
84	            AppError::Internal(msg) => {
85	                (Status::InternalServerError, Json(ApiError::internal(msg)))
86	            }
87	        }
88	    }
89	}
