23	pub async fn check_availability(pool: &MySqlPool, resource_uuid: &str, date: &str) -> Result<Vec<AvailabilitySlot>, AppError> {
24	    let resource = booking_repo::find_resource_by_uuid(pool, resource_uuid).await?
25	        .ok_or_else(|| AppError::NotFound("Resource not found".to_string()))?;
26	
27	    let start_str = format!("{} {}", date, resource.open_time.format("%H:%M:%S"));
28	    let close_str = format!("{} {}", date, resource.close_time.format("%H:%M:%S"));
29	
30	    let existing = booking_repo::find_conflicts(pool, resource.id, &start_str, &close_str).await?;
31	    let blackouts = booking_repo::list_blackouts(pool, resource.id).await?;
32	
33	    // Generate hourly slots
34	    let mut slots = Vec::new();
35	    let open_hour = resource.open_time.hour() as i64;
36	    let close_hour = resource.close_time.hour() as i64;
37	
38	    for hour in open_hour..close_hour {
39	        let slot_start = format!("{} {:02}:00:00", date, hour);
40	        let slot_end = format!("{} {:02}:00:00", date, hour + 1);
41	
42	        let conflict = existing.iter().any(|b| {
43	            let bs = b.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
44	            let be = b.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
45	            bs < slot_end && be > slot_start
46	        });
47	
48	        let blackout = blackouts.iter().any(|bl| {
49	            let bs = bl.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
50	            let be = bl.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
51	            bs < slot_end && be > slot_start
52	        });
53	
54	        let (available, reason) = if blackout {
55	            (false, Some("Maintenance blackout".to_string()))
56	        } else if conflict {
57	            (false, Some("Already booked".to_string()))
58	        } else {
59	            (true, None)
60	        };
61	
62	        slots.push(AvailabilitySlot {
63	            start: slot_start, end: slot_end, available, conflict_reason: reason,
64	        });
65	    }
66	    Ok(slots)
67	}
