69	pub async fn create_booking(
70	    pool: &MySqlPool, req: &CreateBookingRequest, user_id: i64, correlation_id: Option<&str>,
71	) -> Result<BookingResponse, AppError> {
72	    let resource = booking_repo::find_resource_by_uuid(pool, &req.resource_uuid).await?
73	        .ok_or_else(|| AppError::NotFound("Resource not found".to_string()))?;
74	
75	    // Check user doesn't have active booking restriction
76	    if booking_repo::has_active_restriction(pool, user_id, "booking_suspended").await? {
77	        return Err(AppError::Forbidden("You have an active booking restriction due to policy breaches".to_string()));
78	    }
79	
80	    // Enforce active term acceptance
81	    term_service::check_active_term_accepted(pool, user_id).await?;
82	
83	    // Parse times
84	    let start_dt = parse_datetime(&req.start_time)?;
85	    let end_dt = parse_datetime(&req.end_time)?;
86	    let now = Utc::now().naive_utc();
87	
88	    // Validate: end > start
89	    if end_dt <= start_dt {
90	        return Err(AppError::Validation("End time must be after start time".to_string()));
91	    }
92	
93	    // Validate: max 90 days ahead
94	    let max_future = now + Duration::days(MAX_ADVANCE_DAYS);
95	    if start_dt > max_future {
96	        return Err(AppError::Validation(format!("Cannot book more than {} days in advance", MAX_ADVANCE_DAYS)));
97	    }
98	
99	    // Validate: within operating hours
100	    let start_time_only = start_dt.time();
101	    let end_time_only = end_dt.time();
102	    if start_time_only < resource.open_time || end_time_only > resource.close_time {
103	        return Err(AppError::Validation(format!(
104	            "Booking must be within resource hours: {} - {}",
105	            resource.open_time.format("%H:%M"), resource.close_time.format("%H:%M")
106	        )));
107	    }
108	
109	    // Validate: max duration for room type (use minutes for precision)
110	    let duration_minutes = (end_dt - start_dt).num_minutes();
111	    if duration_minutes > (resource.max_booking_hours as i64) * 60 {
112	        return Err(AppError::Validation(format!(
113	            "Maximum booking duration for this resource is {} hours", resource.max_booking_hours
114	        )));
115	    }
116	
117	    // Validate: max 2 active reservations per user per resource
118	    let active_count = booking_repo::count_active_bookings_for_resource(pool, user_id, resource.id).await?;
119	    if active_count >= MAX_ACTIVE_PER_RESOURCE as i64 {
120	        return Err(AppError::Validation(format!(
121	            "Maximum {} active reservations per resource", MAX_ACTIVE_PER_RESOURCE
122	        )));
123	    }
124	
125	    let uuid = Uuid::new_v4().to_string();
126	    let start_str = start_dt.format("%Y-%m-%d %H:%M:%S").to_string();
127	    let end_str = end_dt.format("%Y-%m-%d %H:%M:%S").to_string();
128	
129	    // Determine initial status based on resource approval requirement
130	    let initial_status = if resource.requires_approval { "pending" } else { "confirmed" };
131	
132	    // Atomic booking with conflict prevention
133	    booking_repo::create_booking_atomic(
134	        pool, &uuid, resource.id, user_id, &req.title,
135	        req.description.as_deref(), &start_str, &end_str, initial_status,
136	    ).await.map_err(|e| {
137	        let msg = e.to_string();
138	        if msg.contains("BOOKING_CONFLICT") {
139	            AppError::Validation("Time slot conflict: this resource is already booked for the requested time".to_string())
140	        } else if msg.contains("BLACKOUT_CONFLICT") {
141	            AppError::Validation("Resource is under maintenance during the requested time".to_string())
142	        } else {
143	            AppError::Database(e)
144	        }
145	    })?;
146	
147	    let _ = audit_repo::create_audit_log(
148	        pool, &Uuid::new_v4().to_string(), Some(user_id), "booking.create",
149	        "booking", None, None,
150	        Some(&serde_json::json!({"resource": resource.name, "start": start_str, "end": end_str, "status": initial_status})),
151	        None, None, correlation_id,
152	    ).await;
153	
154	    if initial_status == "pending" {
155	        let _ = notification_service::notify_user(
156	            pool, user_id,
157	            "Booking Submitted for Approval",
158	            &format!("Your booking '{}' has been submitted and is pending approval.", req.title),
159	            "booking", Some("booking"), Some(&uuid),
160	        ).await;
161	        let _ = notification_service::notify_role(
162	            pool, "dept_reviewer",
163	            "New Booking Awaiting Approval",
164	            &format!("A booking '{}' for '{}' requires approval.", req.title, resource.name),
165	            "booking", Some("booking"), Some(&uuid),
166	        ).await;
167	    } else {
168	        let _ = notification_service::notify_user(
169	            pool, user_id,
170	            "Booking Confirmed",
171	            &format!("Your booking '{}' has been confirmed.", req.title),
172	            "booking", Some("booking"), Some(&uuid),
173	        ).await;
174	    }
175	
176	    Ok(BookingResponse {
177	        uuid, resource_id: resource.id, resource_name: Some(resource.name),
178	        booked_by: user_id, title: req.title.clone(),
179	        description: req.description.clone(),
180	        start_time: start_str, end_time: end_str,
181	        status: initial_status.to_string(), reschedule_count: 0,
182	        approved_by: None, approved_at: None,
183	        created_at: Utc::now().format("%Y-%m-%dT%H:%M:%S").to_string(),
184	    })
185	}
