187	pub async fn reschedule_booking(
188	    pool: &MySqlPool, booking_uuid: &str, req: &RescheduleRequest, user_id: i64,
189	) -> Result<(), AppError> {
190	    let booking = booking_repo::find_booking_by_uuid(pool, booking_uuid).await?
191	        .ok_or_else(|| AppError::NotFound("Booking not found".to_string()))?;
192	
193	    if booking.booked_by != user_id {
194	        return Err(AppError::Forbidden("You can only reschedule your own bookings".to_string()));
195	    }
196	
197	    if booking.reschedule_count >= MAX_RESCHEDULES {
198	        return Err(AppError::Validation(format!("Maximum {} reschedules allowed", MAX_RESCHEDULES)));
199	    }
200	
201	    if booking.status != "confirmed" {
202	        return Err(AppError::Validation("Only confirmed bookings can be rescheduled".to_string()));
203	    }
204	
205	    let new_start = parse_datetime(&req.new_start_time)?;
206	    let new_end = parse_datetime(&req.new_end_time)?;
207	
208	    if new_end <= new_start {
209	        return Err(AppError::Validation("End time must be after start time".to_string()));
210	    }
211	
212	    let resource = booking_repo::find_resource_by_id(pool, booking.resource_id).await?
213	        .ok_or_else(|| AppError::Internal("Resource not found".to_string()))?;
214	
215	    // Check operating hours
216	    if new_start.time() < resource.open_time || new_end.time() > resource.close_time {
217	        return Err(AppError::Validation("New time must be within resource operating hours".to_string()));
218	    }
219	
220	    // Check duration (use minutes for precision)
221	    let duration_minutes = (new_end - new_start).num_minutes();
222	    if duration_minutes > (resource.max_booking_hours as i64) * 60 {
223	        return Err(AppError::Validation(format!("Max {} hours", resource.max_booking_hours)));
224	    }
225	
226	    let new_start_str = new_start.format("%Y-%m-%d %H:%M:%S").to_string();
227	    let new_end_str = new_end.format("%Y-%m-%d %H:%M:%S").to_string();
228	
229	    let orig_start = booking.start_time.format("%Y-%m-%d %H:%M:%S").to_string();
230	    let orig_end = booking.end_time.format("%Y-%m-%d %H:%M:%S").to_string();
231	
232	    booking_repo::reschedule_booking_atomic(
233	        pool, booking.id, booking.resource_id,
234	        &Uuid::new_v4().to_string(),
235	        booking.reschedule_count + 1,
236	        user_id,
237	        &orig_start, &orig_end,
238	        &new_start_str, &new_end_str,
239	        req.reason.as_deref(),
240	    ).await.map_err(|e| {
241	        if e.to_string().contains("BOOKING_CONFLICT") {
242	            AppError::Validation("New time conflicts with existing booking".to_string())
243	        } else {
244	            AppError::Internal(e.to_string())
245	        }
246	    })?;
247	
248	    Ok(())
249	}
