251	pub async fn cancel_booking(
252	    pool: &MySqlPool, booking_uuid: &str, user_id: i64, role: &str, correlation_id: Option<&str>,
253	) -> Result<(), AppError> {
254	    let booking = booking_repo::find_booking_by_uuid(pool, booking_uuid).await?
255	        .ok_or_else(|| AppError::NotFound("Booking not found".to_string()))?;
256	
257	    if booking.booked_by != user_id && role != "admin" {
258	        return Err(AppError::Forbidden("Not your booking".to_string()));
259	    }
260	
261	    if booking.status == "cancelled" {
262	        return Err(AppError::Validation("Booking already cancelled".to_string()));
263	    }
264	
265	    booking_repo::update_booking_status(pool, booking.id, "cancelled").await?;
266	
267	    // Late cancellation check: within 2 hours of start creates a breach (only for confirmed bookings)
268	    let now = Utc::now().naive_utc();
269	    let hours_until_start = (booking.start_time - now).num_hours();
270	
271	    if booking.status == "confirmed" && hours_until_start < LATE_CANCEL_HOURS && booking.start_time > now {
272	        let breach_uuid = Uuid::new_v4().to_string();
273	        booking_repo::create_breach(
274	            pool, &breach_uuid, booking.booked_by, Some(booking.id),
275	            "late_cancellation", "medium",
276	            &format!("Booking cancelled within {} hours of start time", LATE_CANCEL_HOURS),
277	        ).await?;
278	
279	        let _ = notification_service::notify_user(
280	            pool, booking.booked_by,
281	            "Late Cancellation Recorded",
282	            "A late cancellation breach has been recorded on your account.",
283	            "booking", None, None,
284	        ).await;
285	
286	        // Check if user hit breach threshold -> auto-restrict
287	        let breach_count = booking_repo::count_recent_breaches(pool, booking.booked_by, BREACH_WINDOW_DAYS).await?;
288	        if breach_count >= BREACH_THRESHOLD {
289	            let already_restricted = booking_repo::has_active_restriction(pool, booking.booked_by, "booking_suspended").await?;
290	            if !already_restricted {
291	                let expires = (Utc::now() + Duration::days(30)).format("%Y-%m-%d %H:%M:%S").to_string();
292	                booking_repo::create_restriction(
293	                    pool, &Uuid::new_v4().to_string(), booking.booked_by,
294	                    "booking_suspended",
295	                    &format!("{} breaches in {} days triggered automatic booking suspension", breach_count, BREACH_WINDOW_DAYS),
296	                    user_id, &Utc::now().format("%Y-%m-%d %H:%M:%S").to_string(),
297	                    Some(&expires), breach_count as i32, true,
298	                ).await?;
299	
300	                let _ = security_repo::create_security_event(
301	                    pool, &Uuid::new_v4().to_string(), "booking_auto_restriction", "warning",
302	                    Some(booking.booked_by), None,
303	                    &format!("Auto-restricted: {} breaches in {} days", breach_count, BREACH_WINDOW_DAYS),
304	                    None, correlation_id,
305	                ).await;
306	
307	                let _ = notification_service::notify_user(
308	                    pool, booking.booked_by,
309	                    "Booking Privileges Suspended",
310	                    &format!("{} policy breaches in {} days triggered an automatic booking suspension.", breach_count, BREACH_WINDOW_DAYS),
311	                    "booking", None, None,
312	                ).await;
313	            }
314	        }
315	    }
316	
317	    let _ = audit_repo::create_audit_log(
318	        pool, &Uuid::new_v4().to_string(), Some(user_id), "booking.cancel",
319	        "booking", Some(booking.id), None,
320	        Some(&serde_json::json!({"hours_until_start": hours_until_start})),
321	        None, None, correlation_id,
322	    ).await;
323	
324	    Ok(())
325	}
