1	use sqlx::MySqlPool;
2	use crate::models::booking::*;
3	
4	pub async fn list_resources(pool: &MySqlPool) -> Result<Vec<Resource>, sqlx::Error> {
5	    sqlx::query_as::<_, Resource>("SELECT * FROM resources WHERE is_active = true ORDER BY name")
6	        .fetch_all(pool).await
7	}
