10	    sqlx::query_as::<_, Resource>("SELECT * FROM resources WHERE uuid = ?")
11	        .bind(uuid).fetch_optional(pool).await
12	}
13	
14	pub async fn find_resource_by_id(pool: &MySqlPool, id: i64) -> Result<Option<Resource>, sqlx::Error> {
15	    sqlx::query_as::<_, Resource>("SELECT * FROM resources WHERE id = ?")
16	        .bind(id).fetch_optional(pool).await
17	}
