19	/// Create booking using SELECT FOR UPDATE to prevent double-booking under concurrency.
20	/// Returns Ok(last_insert_id) or Err if conflict detected within the transaction.
21	pub async fn create_booking_atomic(
22	    pool: &MySqlPool, uuid: &str, resource_id: i64, booked_by: i64,
23	    title: &str, description: Option<&str>, start_time: &str, end_time: &str,
24	    status: &str,
25	) -> Result<u64, sqlx::Error> {
26	    let mut tx = pool.begin().await?;
27	
28	    // Lock the resource row to serialize booking insertions for this resource
29	    sqlx::query("SELECT id FROM resources WHERE id = ? FOR UPDATE")
30	        .bind(resource_id).execute(&mut *tx).await?;
31	
32	    // Check for overlapping confirmed/pending bookings
33	    let conflict: Option<(i64,)> = sqlx::query_as(
34	        "SELECT id FROM bookings WHERE resource_id = ? AND status IN ('confirmed', 'pending') AND start_time < ? AND end_time > ? LIMIT 1"
35	    ).bind(resource_id).bind(end_time).bind(start_time)
36	    .fetch_optional(&mut *tx).await?;
37	
38	    if conflict.is_some() {
39	        tx.rollback().await?;
40	        return Err(sqlx::Error::Protocol("BOOKING_CONFLICT: Time slot already booked".to_string()));
41	    }
42	
43	    // Check for maintenance blackout overlap
44	    let blackout: Option<(i64,)> = sqlx::query_as(
45	        "SELECT id FROM resource_blackouts WHERE resource_id = ? AND start_time < ? AND end_time > ? LIMIT 1"
46	    ).bind(resource_id).bind(end_time).bind(start_time)
47	    .fetch_optional(&mut *tx).await?;
48	
49	    if blackout.is_some() {
50	        tx.rollback().await?;
51	        return Err(sqlx::Error::Protocol("BLACKOUT_CONFLICT: Resource under maintenance during requested time".to_string()));
52	    }
53	
54	    let r = sqlx::query(
55	        "INSERT INTO bookings (uuid, resource_id, booked_by, title, description, start_time, end_time, status) VALUES (?, ?, ?, ?, ?, ?, ?, ?)"
56	    ).bind(uuid).bind(resource_id).bind(booked_by).bind(title).bind(description)
57	    .bind(start_time).bind(end_time).bind(status)
58	    .execute(&mut *tx).await?;
59	
60	    tx.commit().await?;
61	    Ok(r.last_insert_id())
62	}
63	
64	/// Reschedule an existing booking atomically.
65	///
66	/// Acquires a row-level lock on the resource (SELECT FOR UPDATE) inside a
67	/// transaction so that two concurrent reschedules to the same slot cannot both
68	/// pass the conflict check. Returns Ok(()) on success or a `BOOKING_CONFLICT`
69	/// protocol error if the new slot overlaps another booking.
70	pub async fn reschedule_booking_atomic(
71	    pool: &MySqlPool,
72	    booking_id: i64,
73	    resource_id: i64,
74	    reschedule_uuid: &str,
75	    reschedule_number: i32,
76	    requested_by: i64,
77	    orig_start: &str,
78	    orig_end: &str,
79	    new_start: &str,
80	    new_end: &str,
81	    reason: Option<&str>,
82	) -> Result<(), sqlx::Error> {
83	    let mut tx = pool.begin().await?;
84	
85	    // Lock resource row — serializes concurrent reschedule + create operations
86	    sqlx::query("SELECT id FROM resources WHERE id = ? FOR UPDATE")
87	        .bind(resource_id).execute(&mut *tx).await?;
88	
89	    // Conflict check (exclude the booking being rescheduled)
90	    let conflict: Option<(i64,)> = sqlx::query_as(
91	        "SELECT id FROM bookings WHERE resource_id = ? AND id != ? \
92	         AND status IN ('confirmed', 'pending') \
93	         AND start_time < ? AND end_time > ? LIMIT 1"
94	    ).bind(resource_id).bind(booking_id).bind(new_end).bind(new_start)
95	    .fetch_optional(&mut *tx).await?;
96	
97	    if conflict.is_some() {
98	        tx.rollback().await?;
99	        return Err(sqlx::Error::Protocol("BOOKING_CONFLICT: Time slot already booked".to_string()));
100	    }
101	
102	    // Record reschedule history
103	    sqlx::query(
104	        "INSERT INTO booking_reschedules (uuid, booking_id, reschedule_number, requested_by, \
105	         original_start, original_end, new_start, new_end, reason, status) \
106	         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, 'approved')"
107	    ).bind(reschedule_uuid).bind(booking_id).bind(reschedule_number).bind(requested_by)
108	    .bind(orig_start).bind(orig_end).bind(new_start).bind(new_end).bind(reason)
109	    .execute(&mut *tx).await?;
110	
111	    // Update booking times and reschedule counter atomically
112	    sqlx::query("UPDATE bookings SET start_time = ?, end_time = ?, updated_at = NOW() WHERE id = ?")
113	        .bind(new_start).bind(new_end).bind(booking_id)
114	        .execute(&mut *tx).await?;
115	
116	    sqlx::query("UPDATE bookings SET reschedule_count = reschedule_count + 1, updated_at = NOW() WHERE id = ?")
117	        .bind(booking_id).execute(&mut *tx).await?;
118	
119	    tx.commit().await?;
120	    Ok(())
121	}
