1	use sqlx::MySqlPool;
2	use uuid::Uuid;
3	
4	use crate::auth::jwt::generate_token;
5	use crate::auth::password::{verify_password, hash_password, validate_password_complexity};
6	use crate::config::AppConfig;
7	use crate::dto::auth::{LoginResponse, UserInfo};
8	use crate::repositories::{user_repo, security_repo};
9	use crate::utils::errors::AppError;
10	
11	pub async fn login(
12	    pool: &MySqlPool,
13	    config: &AppConfig,
14	    username: &str,
15	    password: &str,
16	    ip_address: Option<&str>,
17	    correlation_id: Option<&str>,
18	) -> Result<LoginResponse, AppError> {
19	    let user = user_repo::find_by_username(pool, username)
20	        .await?
21	        .ok_or_else(|| {
22	            // Log failed login for non-existent user
23	            AppError::Auth("Invalid username or password".to_string())
24	        });
25	
26	    let user = match user {
27	        Ok(u) => u,
28	        Err(e) => {
29	            let _ = security_repo::create_security_event(
30	                pool, &Uuid::new_v4().to_string(), "failed_login", "warning",
31	                None, ip_address, &format!("Failed login attempt for username: {}", username),
32	                None, correlation_id,
33	            ).await;
34	            return Err(e);
35	        }
36	    };
37	
38	    let valid = verify_password(password, &user.password_hash)
39	        .map_err(|_| AppError::Internal("Password verification failed".to_string()))?;
40	
41	    if !valid {
42	        let _ = security_repo::create_security_event(
43	            pool, &Uuid::new_v4().to_string(), "failed_login", "warning",
44	            Some(user.id), ip_address,
45	            &format!("Failed login: invalid password for user {}", username),
46	            None, correlation_id,
47	        ).await;
48	        return Err(AppError::Auth("Invalid username or password".to_string()));
49	    }
50	
51	    let _ = user_repo::update_last_login(pool, user.id).await;
52	
53	    let (token, expires_in) = generate_token(
54	        config, user.id, &user.uuid, &user.username, &user.role, user.department_id,
55	    ).map_err(|e| AppError::Internal(format!("Token generation failed: {e}")))?;
56	
57	    Ok(LoginResponse {
58	        token,
59	        token_type: "Bearer".to_string(),
60	        expires_in,
61	        user: UserInfo {
62	            uuid: user.uuid,
63	            username: user.username,
64	            email: user.email,
65	            full_name: user.full_name,
66	            role: user.role,
67	            department_id: user.department_id,
68	        },
69	    })
70	}
71	
72	pub async fn change_password(
73	    pool: &MySqlPool,
74	    user_id: i64,
75	    current_password: &str,
76	    new_password: &str,
77	    ip_address: Option<&str>,
78	    correlation_id: Option<&str>,
79	) -> Result<(), AppError> {
80	    let user = user_repo::find_by_id(pool, user_id)
81	        .await?
82	        .ok_or_else(|| AppError::NotFound("User not found".to_string()))?;
83	
84	    let valid = verify_password(current_password, &user.password_hash)
85	        .map_err(|_| AppError::Internal("Password verification failed".to_string()))?;
86	
87	    if !valid {
88	        let _ = security_repo::create_security_event(
89	            pool, &Uuid::new_v4().to_string(), "password_change_failed", "warning",
90	            Some(user_id), ip_address, "Password change failed: invalid current password",
91	            None, correlation_id,
92	        ).await;
93	        return Err(AppError::Auth("Current password is incorrect".to_string()));
94	    }
95	
96	    validate_password_complexity(new_password)
97	        .map_err(|errs| AppError::Validation(errs.join("; ")))?;
98	
99	    let new_hash = hash_password(new_password)
100	        .map_err(|_| AppError::Internal("Password hashing failed".to_string()))?;
101	
102	    user_repo::update_password(pool, user_id, &new_hash).await?;
103	
104	    let _ = security_repo::create_security_event(
105	        pool, &Uuid::new_v4().to_string(), "password_changed", "info",
106	        Some(user_id), ip_address, "Password changed successfully",
107	        None, correlation_id,
108	    ).await;
109	
110	    Ok(())
111	}
112	
113	pub async fn reauth(
114	    pool: &MySqlPool,
115	    user_id: i64,
116	    password: &str,
117	    ip_address: Option<&str>,
118	    correlation_id: Option<&str>,
119	) -> Result<(), AppError> {
120	    let user = user_repo::find_by_id(pool, user_id)
121	        .await?
122	        .ok_or_else(|| AppError::NotFound("User not found".to_string()))?;
123	
124	    let valid = verify_password(password, &user.password_hash)
125	        .map_err(|_| AppError::Internal("Password verification failed".to_string()))?;
126	
127	    if !valid {
128	        let _ = security_repo::create_security_event(
129	            pool, &Uuid::new_v4().to_string(), "reauth_failed", "warning",
130	            Some(user_id), ip_address, "Re-authentication failed: invalid password",
131	            None, correlation_id,
132	        ).await;
133	        return Err(AppError::Auth("Invalid password".to_string()));
134	    }
135	
136	    user_repo::update_last_reauth(pool, user_id).await?;
137	    Ok(())
138	}
