        let msg = validation_errors
            .field_errors()
            .values()
            .flat_map(|errs| errs.iter().filter_map(|e| e.message.as_ref().map(|m| m.to_string())))
            .collect::<Vec<_>>()
            .join("; ");
        return Err((Status::BadRequest, Json(ApiError::bad_request(msg))));
    }

    // IP-based rate limiting: 10 attempts/minute, 30 attempts/hour
    let ip = &client_ip.0;
    let rate_exceeded = login_rate_limit_repo::check_ip_rate(pool.inner(), ip, "/auth/login", 10, 30)
        .await.unwrap_or(false);
