15	/// Evaluate active risk rules that are due for a run.
16	///
17	/// Called on every job-loop tick (see `JOB_TICK_SECONDS`). Internally
18	/// delegates to `risk_service::run_risk_evaluation`, which queries:
19	///
20	/// ```sql
21	/// WHERE last_run_at IS NULL
22	///    OR last_run_at < NOW() - INTERVAL schedule_interval_minutes MINUTE
23	/// ```
24	///
25	/// Rules not yet due are skipped without side-effects. The default seed sets
26	/// each rule's `schedule_interval_minutes = 15`, so rules run at most once
27	/// every 15 minutes regardless of how frequently the loop ticks.
28	pub async fn run_risk_evaluation(pool: &MySqlPool) -> Result<u32, Box<dyn std::error::Error>> {
29	    let count = risk_service::run_risk_evaluation(pool).await?;
30	    if count > 0 {
31	        tracing::info!(count = count, "Risk evaluation created new events");
32	    }
33	    Ok(count)
34	}
35	
36	/// Process pending webhook deliveries with retry/backoff
37	pub async fn process_webhooks(pool: &MySqlPool) -> Result<(u32, u32), Box<dyn std::error::Error>> {
38	    let (delivered, failed) = webhook_service::process_webhook_queue(pool).await?;
39	    if delivered > 0 || failed > 0 {
40	        tracing::info!(delivered = delivered, failed = failed, "Webhook processing completed");
41	    }
42	    Ok((delivered, failed))
43	}
44	
45	/// Clean up expired rate limit entries, nonces, and expired version snapshots
46	pub async fn cleanup_expired_data(pool: &MySqlPool) -> Result<(), Box<dyn std::error::Error>> {
47	    let cleaned = rate_limit_repo::cleanup_old_entries(pool).await?;
48	    if cleaned > 0 {
49	        tracing::debug!(cleaned = cleaned, "Cleaned up expired rate limit entries");
50	    }
51	
52	    sqlx::query("DELETE FROM used_nonces WHERE expires_at < NOW()")
53	        .execute(pool).await?;
