8	pub fn CourseDetail(uuid: String) -> Element {
9	    let mut course = use_signal(|| None::<CourseResponse>);
10	    let mut sections = use_signal(|| Vec::<SectionResponse>::new());
11	    let mut versions = use_signal(|| Vec::<VersionResponse>::new());
