22	        let u = uuid_clone.clone();
23	        spawn(async move {
24	            loading.set(true);
25	            if let Ok(r) = api::get_course(&u).await { course.set(Some(r.data)); }
26	            if let Ok(r) = api::get_sections(&u).await { sections.set(r.data); }
27	            if let Ok(r) = api::get_versions(&u).await { versions.set(r.data); }
28	            loading.set(false);
29	        });
30	    });
31	
32	    let handle_submit_approval = {
33	        let uuid = uuid.clone();
34	        move |evt: Event<FormData>| {
35	            evt.prevent_default();
36	            let rn = release_notes.read().clone();
37	            let ed = effective_date.read().clone();
38	            let u = uuid.clone();
39	            spawn(async move {
40	                match api::submit_for_approval(&u, &rn, &ed).await {
41	                    Ok(_) => {
42	                        ToastManager::success("Submitted for approval");
43	                        show_submit.set(false);
44	                        if let Ok(r) = api::get_course(&u).await { course.set(Some(r.data)); }
45	                    }
46	                    Err(e) => ToastManager::error(format!("Failed: {}", e)),
47	                }
48	            });
49	        }
50	    };
51	
52	    if *loading.read() {
53	        return rsx! { LoadingSpinner {} };
54	    }
55	
56	    let c = match course.read().as_ref() {
57	        Some(c) => c.clone(),
58	        None => return rsx! { EmptyState { title: "Course not found".to_string() } },
59	    };
60	
61	    rsx! {
62	        div { class: "page",
63	            div { class: "page-header",
64	                div { class: "page-header-row",
65	                    div {
66	                        h1 { "{c.title}" }
67	                        div { class: "page-meta",
68	                            span { class: "meta-code", "{c.code}" }
69	                            StatusBadge { status: c.status.clone() }
70	                            span { class: "meta-version", "v{c.current_version}" }
71	                            if let Some(ref upd) = c.updated_on {
72	                                span { class: "meta-muted", "Updated: {upd}" }
73	                            }
74	                        }
75	                    }
76	                    div { class: "page-actions",
77	                        if can_author && (c.status == "draft" || c.status == "rejected") {
78	                            Link { to: crate::Route::CourseEditor { uuid: c.uuid.clone() }, class: "btn btn-outline", "Edit" }
79	                            button { class: "btn btn-primary", onclick: move |_| show_submit.set(true), "Submit for Approval" }
80	                        }
81	                    }
82	                }
83	            }
84	
85	            if let Some(ref desc) = c.description {
86	                p { class: "course-description", "{desc}" }
87	            }
88	
89	            if !c.tags.is_empty() {
90	                div { class: "tag-list",
91	                    for tag in c.tags.iter() {
92	                        span { class: "tag", "{tag.name}" }
93	                    }
94	                }
95	            }
96	
97	            // Tabs
98	            div { class: "tabs",
99	                button { class: if *active_tab.read() == "content" { "tab active" } else { "tab" }, onclick: move |_| active_tab.set("content"), "Content" }
100	                button { class: if *active_tab.read() == "versions" { "tab active" } else { "tab" }, onclick: move |_| active_tab.set("versions"), "Versions ({versions.read().len()})" }
101	            }
102	
103	            if *active_tab.read() == "content" {
104	                if sections.read().is_empty() {
105	                    EmptyState { title: "No sections yet".to_string() }
106	                } else {
107	                    for sec in sections.read().iter() {
108	                        div { class: "section-card",
109	                            h3 { class: "section-title", "{sec.title}" }
110	                            if sec.lessons.is_empty() {
111	                                p { class: "text-muted", "No lessons" }
112	                            }
113	                            for lesson in sec.lessons.iter() {
114	                                div { class: "lesson-row",
115	                                    span { class: "lesson-type badge badge-default", "{lesson.content_type}" }
116	                                    span { class: "lesson-title", "{lesson.title}" }
117	                                    if let Some(dur) = lesson.duration_minutes {
118	                                        span { class: "lesson-duration", "{dur} min" }
119	                                    }
120	                                }
121	                            }
122	                        }
123	                    }
124	                }
125	            }
126	
127	            if *active_tab.read() == "versions" {
128	                if versions.read().is_empty() {
129	                    EmptyState { title: "No versions yet".to_string() }
130	                } else {
131	                    DataTable { headers: vec!["Version".into(), "Summary".into(), "Created".into(), "Expires".into()],
132	                        for v in versions.read().iter() {
133	                            tr {
134	                                td { "v{v.version_number}" }
135	                                td { "{v.change_summary.clone().unwrap_or_default()}" }
136	                                td { class: "td-muted", "{v.created_at}" }
137	                                td { class: "td-muted", "{v.expires_at.clone().unwrap_or_else(|| \"--\".to_string())}" }
138	                            }
139	                        }
140	                    }
141	                }
142	            }
143	
144	            if *show_submit.read() {
145	                Modal { title: "Submit for Approval".to_string(), on_close: move |_| show_submit.set(false),
146	                    form { class: "form", onsubmit: handle_submit_approval,
147	                        div { class: "form-group",
148	                            label { "Release Notes (required)" }
149	                            textarea { class: "form-input form-textarea", required: true, placeholder: "Describe what changed...", value: "{release_notes}", oninput: move |e| release_notes.set(e.value()) }
150	                        }
151	                        div { class: "form-group",
152	                            label { "Effective Date (MM/DD/YYYY HH:MM AM/PM)" }
153	                            input { class: "form-input", required: true, placeholder: "e.g. 06/15/2025 09:00 AM", value: "{effective_date}", oninput: move |e| effective_date.set(e.value()) }
154	                        }
155	                        button { r#type: "submit", class: "btn btn-primary btn-full", "Submit" }
156	                    }
157	                }
158	            }
159	        }
160	    }
161	}
