7	pub fn Bookings() -> Element {
8	    let mut resources = use_signal(|| Vec::<ResourceResponse>::new());
9	    let mut bookings = use_signal(|| Vec::<BookingResponse>::new());
10	    let mut breaches = use_signal(|| Vec::<BreachResponse>::new());
11	    let mut restrictions = use_signal(|| Vec::<RestrictionResponse>::new());
12	    let mut loading = use_signal(|| true);
13	    let mut active_tab = use_signal(|| "bookings");
14	    let mut show_book = use_signal(|| false);
15	    let mut sel_resource = use_signal(String::new);
16	    let mut book_title = use_signal(String::new);
17	    let mut book_start = use_signal(String::new);
18	    let mut book_end = use_signal(String::new);
19	    let mut show_reschedule = use_signal(|| None::<String>);
20	    let mut new_start = use_signal(String::new);
21	    let mut new_end = use_signal(String::new);
22	    let mut reschedule_reason = use_signal(String::new);
23	
24	    let reload = move || {
25	        spawn(async move {
26	            loading.set(true);
27	            if let Ok(r) = api::list_resources().await { resources.set(r.data); }
28	            if let Ok(r) = api::my_bookings().await { bookings.set(r.data); }
29	            if let Ok(r) = api::my_breaches().await { breaches.set(r.data); }
30	            if let Ok(r) = api::my_restrictions().await { restrictions.set(r.data); }
31	            loading.set(false);
32	        });
33	    };
34	
35	    use_effect(move || { reload(); });
36	
37	    let handle_book = move |evt: Event<FormData>| {
38	        evt.prevent_default();
39	        let r_uuid = sel_resource.read().clone();
40	        let t = book_title.read().clone();
41	        let s = book_start.read().clone();
42	        let e = book_end.read().clone();
43	        spawn(async move {
44	            match api::create_booking(&r_uuid, &t, &s, &e).await {
45	                Ok(_) => {
46	                    ToastManager::success("Booking created!");
47	                    show_book.set(false);
48	                    book_title.set(String::new());
49	                    book_start.set(String::new());
50	                    book_end.set(String::new());
51	                    if let Ok(r) = api::my_bookings().await { bookings.set(r.data); }
52	                }
53	                Err(e) => ToastManager::error(format!("{}", e)),
54	            }
55	        });
56	    };
57	
58	    let handle_cancel = move |uuid: String| {
59	        spawn(async move {
60	            match api::cancel_booking(&uuid).await {
61	                Ok(_) => {
62	                    ToastManager::success("Booking cancelled");
63	                    if let Ok(r) = api::my_bookings().await { bookings.set(r.data); }
64	                    if let Ok(r) = api::my_breaches().await { breaches.set(r.data); }
65	                }
66	                Err(e) => ToastManager::error(format!("{}", e)),
67	            }
68	        });
69	    };
70	
71	    let handle_reschedule = move |_: Event<MouseData>| {
72	        let uuid = show_reschedule.read().clone();
73	        let ns = new_start.read().clone();
74	        let ne = new_end.read().clone();
75	        let reason = reschedule_reason.read().clone();
76	        spawn(async move {
77	            if let Some(u) = uuid {
78	                let r = if reason.is_empty() { None } else { Some(reason.as_str()) };
79	                match api::reschedule_booking(&u, &ns, &ne, r).await {
80	                    Ok(_) => {
81	                        ToastManager::success("Rescheduled");
82	                        show_reschedule.set(None);
83	                        if let Ok(r) = api::my_bookings().await { bookings.set(r.data); }
84	                    }
85	                    Err(e) => ToastManager::error(format!("{}", e)),
86	                }
87	            }
88	        });
89	    };
90	
91	    if *loading.read() {
92	        return rsx! { LoadingSpinner {} };
93	    }
94	
95	    rsx! {
96	        div { class: "page",
97	            div { class: "page-header",
98	                div { class: "page-header-row",
99	                    h1 { "Bookings" }
100	                    button { class: "btn btn-primary", onclick: move |_| show_book.set(true), "+ New Booking" }
101	                }
102	                if !restrictions.read().is_empty() {
103	                    div { class: "alert alert-danger",
104	                        "You have active booking restrictions. Some actions may be unavailable."
105	                    }
106	                }
107	            }
108	
109	            div { class: "tabs",
110	                button { class: if *active_tab.read() == "bookings" { "tab active" } else { "tab" }, onclick: move |_| active_tab.set("bookings"), "My Bookings" }
111	                button { class: if *active_tab.read() == "resources" { "tab active" } else { "tab" }, onclick: move |_| active_tab.set("resources"), "Resources" }
112	                button { class: if *active_tab.read() == "breaches" { "tab active" } else { "tab" }, onclick: move |_| active_tab.set("breaches"),
113	                    "Breaches"
114	                    if !breaches.read().is_empty() {
115	                        span { class: "tab-badge", "{breaches.read().len()}" }
116	                    }
117	                }
118	            }
119	
120	            if *active_tab.read() == "bookings" {
121	                if bookings.read().is_empty() {
122	                    EmptyState { title: "No bookings".to_string(), description: Some("Book a resource to get started.".to_string()) }
123	                } else {
124	                    DataTable { headers: vec!["Resource".into(), "Title".into(), "Start".into(), "End".into(), "Status".into(), "Reschedules".into(), "Actions".into()],
125	                        for b in bookings.read().iter() {
126	                            tr {
127	                                td { "{b.resource_name.clone().unwrap_or_default()}" }
128	                                td { "{b.title}" }
129	                                td { class: "td-muted", "{b.start_time}" }
130	                                td { class: "td-muted", "{b.end_time}" }
131	                                td { StatusBadge { status: b.status.clone() } }
132	                                td { "{b.reschedule_count}/2" }
133	                                td {
134	                                    if b.status == "confirmed" {
135	                                        div { class: "btn-row-inline",
136	                                            if b.reschedule_count < 2 {
137	                                                button {
138	                                                    class: "btn btn-xs btn-outline",
139	                                                    onclick: { let u = b.uuid.clone(); move |_| show_reschedule.set(Some(u.clone())) },
140	                                                    "Reschedule"
141	                                                }
142	                                            }
143	                                            button {
144	                                                class: "btn btn-xs btn-danger-outline",
145	                                                onclick: { let u = b.uuid.clone(); move |_| handle_cancel(u.clone()) },
146	                                                "Cancel"
147	                                            }
148	                                        }
149	                                    }
150	                                }
151	                            }
152	                        }
153	                    }
154	                }
155	            }
156	
157	            if *active_tab.read() == "resources" {
158	                div { class: "resource-grid",
159	                    for r in resources.read().iter() {
160	                        div { class: "resource-card",
161	                            h3 { "{r.name}" }
162	                            div { class: "resource-meta",
163	                                span { class: "badge badge-default", "{r.resource_type}" }
164	                                if let Some(ref loc) = r.location { span { class: "meta-muted", "{loc}" } }
165	                            }
166	                            if let Some(cap) = r.capacity { p { class: "meta-muted", "Capacity: {cap}" } }
167	                            p { class: "meta-muted", "Hours: {r.open_time} - {r.close_time}" }
168	                            p { class: "meta-muted", "Max booking: {r.max_booking_hours}h" }
169	                        }
170	                    }
171	                }
172	            }
173	
174	            if *active_tab.read() == "breaches" {
175	                if breaches.read().is_empty() {
176	                    EmptyState { title: "No breaches".to_string(), description: Some("Clean record!".to_string()) }
177	                } else {
178	                    DataTable { headers: vec!["Type".into(), "Severity".into(), "Description".into(), "Status".into(), "Date".into()],
179	                        for b in breaches.read().iter() {
180	                            tr {
181	                                td { "{b.breach_type}" }
182	                                td { StatusBadge { status: b.severity.clone() } }
183	                                td { "{b.description}" }
184	                                td { StatusBadge { status: b.status.clone() } }
185	                                td { class: "td-muted", "{b.created_at}" }
186	                            }
187	                        }
188	                    }
189	                }
190	            }
191	
192	            if *show_book.read() {
193	                Modal { title: "New Booking".to_string(), on_close: move |_| show_book.set(false),
194	                    form { class: "form", onsubmit: handle_book,
195	                        div { class: "form-group",
196	                            label { "Resource" }
197	                            select { class: "form-input", required: true, value: "{sel_resource}", onchange: move |e| sel_resource.set(e.value()),
198	                                option { value: "", "Select resource..." }
199	                                for r in resources.read().iter() {
200	                                    option { value: "{r.uuid}", "{r.name} ({r.resource_type})" }
201	                                }
202	                            }
203	                        }
204	                        div { class: "form-group",
205	                            label { "Title" }
206	                            input { class: "form-input", required: true, placeholder: "Meeting title", value: "{book_title}", oninput: move |e| book_title.set(e.value()) }
207	                        }
208	                        div { class: "form-row",
209	                            div { class: "form-group form-half",
210	                                label { "Start (YYYY-MM-DD HH:MM:SS)" }
211	                                input { class: "form-input", required: true, placeholder: "2025-06-15 10:00:00", value: "{book_start}", oninput: move |e| book_start.set(e.value()) }
212	                            }
213	                            div { class: "form-group form-half",
214	                                label { "End" }
215	                                input { class: "form-input", required: true, placeholder: "2025-06-15 12:00:00", value: "{book_end}", oninput: move |e| book_end.set(e.value()) }
216	                            }
217	                        }
218	                        div { class: "form-help", "Rules: max 90 days ahead, max 2 active per resource, max {resources.read().first().map(|r| r.max_booking_hours).unwrap_or(4)}h for rooms" }
219	                        button { r#type: "submit", class: "btn btn-primary btn-full", "Book" }
220	                    }
221	                }
222	            }
223	
224	            if show_reschedule.read().is_some() {
225	                Modal { title: "Reschedule Booking".to_string(), on_close: move |_| show_reschedule.set(None),
226	                    div { class: "form",
227	                        div { class: "form-group",
228	                            label { "New Start" }
229	                            input { class: "form-input", placeholder: "YYYY-MM-DD HH:MM:SS", value: "{new_start}", oninput: move |e| new_start.set(e.value()) }
230	                        }
231	                        div { class: "form-group",
232	                            label { "New End" }
233	                            input { class: "form-input", placeholder: "YYYY-MM-DD HH:MM:SS", value: "{new_end}", oninput: move |e| new_end.set(e.value()) }
234	                        }
