236	                            label { "Reason" }
237	                            input { class: "form-input", placeholder: "Optional", value: "{reschedule_reason}", oninput: move |e| reschedule_reason.set(e.value()) }
238	                        }
239	                        button { class: "btn btn-primary btn-full", onclick: handle_reschedule, "Reschedule" }
