6	use crate::auth::hmac;
7	use crate::config::AppConfig;
8	use crate::utils::errors::ApiError;
9	
10	pub struct HmacVerified {
11	    pub key_id: String,
12	}
13	
14	#[rocket::async_trait]
15	impl<'r> FromRequest<'r> for HmacVerified {
16	    type Error = Json<ApiError>;
17	
18	    async fn from_request(req: &'r Request<'_>) -> Outcome<Self, Self::Error> {
19	        let config = req.rocket().state::<AppConfig>().expect("AppConfig not configured");
20	        let pool = req.rocket().state::<MySqlPool>().expect("DB pool not configured");
21	
22	        let key_id = match req.headers().get_one("X-HMAC-Key-Id") {
23	            Some(k) => k.to_string(),
24	            None => return Outcome::Error((
25	                Status::Unauthorized,
26	                Json(ApiError::unauthorized("Missing X-HMAC-Key-Id header")),
27	            )),
28	        };
29	
30	        let nonce = match req.headers().get_one("X-HMAC-Nonce") {
31	            Some(n) => n.to_string(),
32	            None => return Outcome::Error((
33	                Status::Unauthorized,
34	                Json(ApiError::unauthorized("Missing X-HMAC-Nonce header")),
35	            )),
36	        };
37	
38	        let timestamp: i64 = match req.headers().get_one("X-HMAC-Timestamp").and_then(|t| t.parse().ok()) {
39	            Some(t) => t,
40	            None => return Outcome::Error((
41	                Status::Unauthorized,
42	                Json(ApiError::unauthorized("Missing or invalid X-HMAC-Timestamp header")),
43	            )),
44	        };
45	
46	        let signature = match req.headers().get_one("X-HMAC-Signature") {
47	            Some(s) => s.to_string(),
48	            None => return Outcome::Error((
49	                Status::Unauthorized,
50	                Json(ApiError::unauthorized("Missing X-HMAC-Signature header")),
51	            )),
52	        };
53	
54	        // Validate timestamp freshness
55	        if !hmac::is_timestamp_valid(timestamp, config.hmac_nonce_expiry_seconds) {
56	            return Outcome::Error((
57	                Status::Unauthorized,
58	                Json(ApiError::unauthorized("Request timestamp expired")),
59	            ));
60	        }
61	
62	        // Check nonce not reused
63	        let nonce_exists: Option<(i64,)> = sqlx::query_as(
64	            "SELECT id FROM used_nonces WHERE nonce = ?"
65	        ).bind(&nonce).fetch_optional(pool).await.unwrap_or(None);
66	
67	        if nonce_exists.is_some() {
68	            return Outcome::Error((
69	                Status::Unauthorized,
70	                Json(ApiError::unauthorized("Nonce already used (replay attack prevented)")),
71	            ));
72	        }
73	
74	        // Look up HMAC key
75	        let key_row: Option<(String,)> = sqlx::query_as(
76	            "SELECT secret_hash FROM hmac_keys WHERE key_id = ? AND is_active = true AND (expires_at IS NULL OR expires_at > NOW())"
77	        ).bind(&key_id).fetch_optional(pool).await.unwrap_or(None);
78	
79	        let secret = match key_row {
80	            Some((s,)) => s,
81	            None => return Outcome::Error((
82	                Status::Unauthorized,
83	                Json(ApiError::unauthorized("Invalid or expired HMAC key")),
84	            )),
85	        };
86	
87	        // Build message and verify — sign method+path, not a client-controlled header
88	        let method = req.method().as_str();
89	        let path = req.uri().path();
90	        let message = hmac::build_signing_message(&key_id, &nonce, timestamp, method, path);
91	
92	        if !hmac::verify_signature(&secret, &message, &signature) {
93	            return Outcome::Error((
94	                Status::Unauthorized,
95	                Json(ApiError::unauthorized("Invalid HMAC signature")),
96	            ));
97	        }
98	
99	        // Store nonce to prevent replay
100	        let _ = sqlx::query(
101	            "INSERT INTO used_nonces (nonce, key_id, expires_at) VALUES (?, ?, DATE_ADD(NOW(), INTERVAL 5 MINUTE))"
102	        ).bind(&nonce).bind(&key_id).execute(pool).await;
103	
104	        Outcome::Success(HmacVerified { key_id })
105	    }
106	}
